	result := map[string]interface{}{
		"count":  len(videos),
		"videos": videos,
	}

	yamlResult, err := yaml.Marshal(result)
	if err != nil {
		return mcp.NewToolResultError(fmt.Sprintf("failed to marshal results: %v", err)), nil
